    @Test
    void testPyIntObjEquals() {
        PyIntObj a = new PyIntObj(42);
        PyIntObj b = new PyIntObj(42);
        PyIntObj c = new PyIntObj(99);
        assertEquals(a, b);
        assertNotEquals(a, c);
        assertEquals(a.hashCode(), b.hashCode());
    }

    @Test
    void testPyIntObjNotEqualToNull() {
        PyIntObj a = new PyIntObj(42);
        assertNotEquals(a, null);
