    void testPyBoolObjEquals() {
        PyBoolObj t1 = new PyBoolObj(true);
        PyBoolObj t2 = new PyBoolObj(true);
        PyBoolObj f1 = new PyBoolObj(false);
        assertEquals(t1, t2);
        assertNotEquals(t1, f1);
        assertEquals(t1.hashCode(), t2.hashCode());
    }

    @Test
    void testPyBoolObjToString() {
        assertEquals("True", new PyBoolObj(true).toString());
        assertEquals("False", new PyBoolObj(false).toString());
