    @Test
    void testPyFloatObjEquals() {
        PyFloatObj a = new PyFloatObj(3.14);
        PyFloatObj b = new PyFloatObj(3.14);
        PyFloatObj c = new PyFloatObj(2.71);
        assertEquals(a, b);
        assertNotEquals(a, c);
        assertEquals(a.hashCode(), b.hashCode());
    }

    @Test
    void testPyFloatObjToString() {
