    // ==================== Dict ====================

    @Test
    void testDictEquals() {
        Map<PyIntObj, PyIntObj> m1 = new LinkedHashMap<>();
        m1.put(new PyIntObj(1), new PyIntObj(2));
        Map<PyIntObj, PyIntObj> m2 = new LinkedHashMap<>();
        m2.put(new PyIntObj(1), new PyIntObj(2));
        assertEquals(new PyDictObj<>(m1), new PyDictObj<>(m2));
    }

    @Test
    void testDictToStringMulti() {
        Map<PyIntObj, PyStringObj> m = new LinkedHashMap<>();
        m.put(new PyIntObj(1), new PyStringObj("a"));
        m.put(new PyIntObj(2), new PyStringObj("b"));
        assertEquals("{1: 'a', 2: 'b'}", new PyDictObj<>(m).toString());
    }

    @Test
    void testNestedDictToString() {
        Map<PyIntObj, PyIntObj> inner = new LinkedHashMap<>();
        inner.put(new PyIntObj(2), new PyIntObj(3));
        Map<PyIntObj, PyDictObj<PyIntObj, PyIntObj>> outer = new LinkedHashMap<>();
        outer.put(new PyIntObj(1), new PyDictObj<>(inner));
        assertEquals("{1: {2: 3}}", new PyDictObj<>(outer).toString());
    }

    // ==================== String ====================

    @Test
    void testStringEquals() {
        PyStringObj a = new PyStringObj("hello");
        PyStringObj b = new PyStringObj("hello");
        PyStringObj c = new PyStringObj("world");
        assertEquals(a, b);
        assertNotEquals(a, c);
        assertEquals(a.hashCode(), b.hashCode());
    }

    @Test
    void testStringToString() {
        assertEquals("'hello'", new PyStringObj("hello").toString());
        assertEquals("'a'", new PyStringObj("a").toString());
    }

    @Test
    void testStringGetValueSize() {
        assertEquals(5, new PyStringObj("hello").getValue().size());
        assertEquals(0, new PyStringObj("").getValue().size());
    }

    // ==================== Deeply nested toString ====================

    @Test
    void testDeeplyNestedToString() {
        // [[{1: (2, 3)}]]
        PyTupleObj<PyIntObj> innerTuple = new PyTupleObj<>(
            Arrays.asList(new PyIntObj(2), new PyIntObj(3)));
        Map<PyIntObj, PyTupleObj<PyIntObj>> innerMap = new LinkedHashMap<>();
        innerMap.put(new PyIntObj(1), innerTuple);
        PyDictObj<PyIntObj, PyTupleObj<PyIntObj>> innerDict = new PyDictObj<>(innerMap);
        PyListObj<PyDictObj<PyIntObj, PyTupleObj<PyIntObj>>> middleList =
            new PyListObj<>(Arrays.asList(innerDict));
        PyListObj<PyListObj<PyDictObj<PyIntObj, PyTupleObj<PyIntObj>>>> deeplyNested =
            new PyListObj<>(Arrays.asList(middleList));
        assertEquals("[[{1: (2, 3)}]]", deeplyNested.toString());
    }

    // ==================== Self-equality ====================

    @Test
    void testSelfEquality() {
        PyIntObj i = new PyIntObj(1);
        assertEquals(i, i);
        PyListObj<PyIntObj> list = new PyListObj<>(Arrays.asList(new PyIntObj(1)));
        assertEquals(list, list);
    }
